/// <reference path="./online-streaming-provider.d.ts" />

class Provider {
    baseUrl = "https://4animo.xyz"
    apiBaseUrl = "https://api.kryzox.xyz"

    getSettings(): Settings {
        return {
            episodeServers: ["HD-1", "HD-2", "HD-3"],
            supportsDub: true,
        }
    }

    async search(query: SearchOptions): Promise<SearchResult[]> {
        const response = await fetch(`${this.apiBaseUrl}/suggestion?keyword=${encodeURIComponent(query.query)}`)
        if (!response.ok) {
            return []
        }

        const items = await response.json()

        if (!Array.isArray(items)) {
            return []
        }

        return items.map((item: any) => ({
            id: `${item.slug}/${query.dub ? "dub" : "sub"}`,
            title: item.title,
            url: `https://4animo.xyz/anime/${item.slug}`, 
            subOrDub: query.dub ? "dub" : "sub",
        }))
    }

    async findEpisodes(animeId: string): Promise<EpisodeDetails[]> {
        const [id, lang] = animeId.split("/")

        const response = await fetch(`${this.baseUrl}/watch/${id}`)
        if (!response.ok) return []
        const html = await response.text()

        const $ = LoadDoc(html)
        const episodes: EpisodeDetails[] = []

        $("button").each((i, el) => {
            const numText = el.find("span").first().text().trim()
            if (!/^\d{1,3}$/.test(numText)) return

            const titleText = el.find("p").first().text().trim()
            const epNumber = parseInt(numText, 10)

            episodes.push({
                id: lang,
                number: epNumber,
                url: `${this.baseUrl}/watch/${id}?ep=${epNumber}`,
                title: titleText || `Episode ${epNumber}`,
            })
        })

        return episodes
    }

    async findEpisodeServer(episode: EpisodeDetails, _server: string): Promise<EpisodeServer> {
        const response = await fetch(episode.url)

        const html = await response.text()

        const iframeRegex = /<iframe[^>]+src=["']([^"']*(?:4animo\.xyz|embed)[^"']*)["']/i
        const iframeMatch = html.match(iframeRegex)

        const iframeUrlStr = iframeMatch[1].replace(/&amp;/g, '&')

        const urlPath = iframeUrlStr.split('?')[0] 
        const segments = urlPath.split('/')

        const embedIndex = segments.indexOf("embed")
        if (embedIndex === -1 || segments.length < embedIndex + 4) {
            return { server: _server, headers: {}, videoSources: [] }
        }

        const id = segments[embedIndex + 2]

        const iframeResponse = await fetch(`https://cdn.4animo.xyz/embed/${_server.toLowerCase()}/${id}/${episode.id}?k=1&autoPlay=1&skipIntro=1&skipOutro=1`, {
            headers: {
                "Referer": episode.url,
                "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"
            }
        })

        const iframeHtml = await iframeResponse.text()

        const cfgRegex = /var\s+cfg\s*=\s*({[\s\S]*?})\s*;/
        const cfgMatch = iframeHtml.match(cfgRegex)

        const m3u8UrlRegex = /const\s+m3u8Url\s*=\s*["']([^"']+)["']/
        const directTracksRegex = /const\s+tracks\s*=\s*(\[[\s\S]*?\])\s*;/

        const m3u8UrlMatch = iframeHtml.match(m3u8UrlRegex)
        const directTracksMatch = iframeHtml.match(directTracksRegex)

        const streamUrl = m3u8UrlMatch[1]
        const rawTracks = directTracksMatch ? JSON.parse(directTracksMatch[1]) : []

        const subtitles = rawTracks
            .filter((track: any) => track.kind === "captions")
            .map((track: any, i: number) => ({
                id: `sub-${i}`,
                url: track.file.startsWith('/') ? `https://cdn.4animo.xyz${track.file}` : track.file,
                language: track.label,
                isDefault: false
            }))

        return {
            server: _server,
            headers: {
                "Referer": `https://cdn.4animo.xyz/embed/${_server.toLowerCase()}/${id}/${episode.id}?k=1&autoPlay=1&skipIntro=1&skipOutro=1`,
                "User-Agent": 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/149.0.0.0 Safari/537.36 Edg/149.0.0.0'
            },
            videoSources: [
                {
                    url: streamUrl.startsWith('/') ? `https://cdn.4animo.xyz${streamUrl}` : streamUrl,
                    quality: "auto",
                    type: "m3u8",
                    subtitles,
                },
            ],
        }
    }
}
